import React from "react"

import SEO from "../components/seo"

const NotFoundPage = () => {
  return (
    <>
      <SEO title="404: Not found" />
      <div
        style={{
          display: "block",
          alignSelf: "center",
          textAlign: "center",
          margin: "3rem",
        }}
      >
        <h1>404: Not Found</h1>
        <p
          style={{
            textAlign: "center",
            margin: "auto",
          }}
        >
          There is no content for this page
        </p>
        <a href="https://hikarintu.github.io/homepage/">Back to home page</a>
      </div>
    </>
  )
}
export default NotFoundPage
